import './UserItem.css';

const UserItem = (props) => {
  return (
    <li className="user-item">
      <div>
        <img src={props.image} alt={props.name} />
      </div>
      <div>
        <h2>{props.name}</h2>
        <h3>{props.placeCount} Places</h3>
      </div>
    </li>
  );
};

export default UserItem;
